input.command:
kubectl -n elasticsearch patch deployment auth-checker --type=strategic -p '{
  "spec": {
    "template": {
      "spec": {
        "containers": [
          {
            "name": "checker",
            "readinessProbe": {
              "exec": {
                "command": [
                  "/bin/sh",
                  "-c",
                  "curl -sk --max-time 5 -u elastic:${ELASTIC_PASSWORD} https://es-http.elasticsearch.svc:9200/_security/_authenticate | grep -q '\"username\":\"elastic\"'"
                ]
              }
            }
          }
        ]
      }
    }
  }
}'
